CREATE OR REPLACE FUNCTION create_audit_partition(month_start DATE) RETURNS VOID AS $$
DECLARE
    partition_name TEXT;
    month_end      DATE;
    grant_sql      TEXT;
BEGIN
    partition_name := 'audit_events_' || to_char(month_start, 'YYYY_MM');
    month_end      := month_start + INTERVAL '1 month';

    IF NOT EXISTS (
        SELECT 1 FROM pg_class c
        JOIN pg_namespace n ON n.oid = c.relnamespace
        WHERE c.relname = partition_name
          AND n.nspname = 'public'
    ) THEN
        EXECUTE format(
            'CREATE TABLE %I PARTITION OF audit_events FOR VALUES FROM (%L) TO (%L)',
            partition_name, month_start, month_end
        );
        grant_sql := format('GRANT INSERT ON %I TO audit_writer', partition_name);
        EXECUTE grant_sql;
    END IF;
END;
$$ LANGUAGE plpgsql;
